#!/usr/bin/env bash
# SLURM job script — generated by run-experiment skill
# Project:  {PROJECT}
# Env:      {ENV_NAME} ({ENV_DISPLAY})
# Created:  {DATE}
# Commit:   {COMMIT}
#
# Submit:   sbatch {SCRIPT_NAME}
# Monitor:  squeue -u $USER
# Logs:     tail -f {LOG_DIR}/slurm-%j.out
# Important: create {LOG_DIR} before calling sbatch.

# ── SLURM directives ──────────────────────────────────────────────────────────
#SBATCH --job-name={JOB_NAME}
#SBATCH --partition={PARTITION}
#SBATCH --nodes=1
#SBATCH --ntasks=1
#SBATCH --cpus-per-task={CPUS}
#SBATCH --gres=gpu:{GPUS}              # remove line for CPU-only jobs
#SBATCH --mem={MEM}
#SBATCH --time={WALLTIME}
#SBATCH --output={LOG_DIR}/slurm-%j.out
#SBATCH --error={LOG_DIR}/slurm-%j.err
#SBATCH --mail-type=END,FAIL           # optional: email on finish/fail
# #SBATCH --mail-user={USER_EMAIL}     # uncomment and set your email
# #SBATCH --array=0-3%2               # uncomment for job arrays

# ── Environment setup ─────────────────────────────────────────────────────────
set -euo pipefail

echo "========================================="
echo "Job ID:     $SLURM_JOB_ID"
echo "Job name:   $SLURM_JOB_NAME"
echo "Node:       $SLURMD_NODENAME"
echo "Partition:  $SLURM_JOB_PARTITION"
echo "GPUs:       $SLURM_GPUS_ON_NODE"
echo "Start:      $(date)"
echo "Project:    {PROJECT}"
echo "Commit:     {COMMIT}"
echo "========================================="

# Load modules (uncomment as needed)
# module load cuda/12.1
# module load anaconda3

# Activate conda environment
# conda activate {CONDA_ENV}

# Or if using uv/venv:
# source {PROJECT_ROOT}/.venv/bin/activate

# Move to project root
cd {PROJECT_ROOT}

# Create output directories
mkdir -p {LOG_DIR}
mkdir -p {OUTPUT_DIR}

# Set scratch as temp dir (important on HPC to avoid filling /tmp)
# export TMPDIR={SCRATCH}/tmp
# mkdir -p $TMPDIR

# ── Experiment ────────────────────────────────────────────────────────────────
echo "Running: {RUN_COMMAND}"
echo "-----------------------------------------"

{RUN_COMMAND}

EXIT_CODE=$?

echo "-----------------------------------------"
echo "End:   $(date)"
echo "Exit:  $EXIT_CODE"
echo "========================================="

exit $EXIT_CODE
